// 获取输入数据
const inputData = $input.first().json;
const fromAddress = inputData.fromAddress;
const toAddress = inputData.toAddress;
const weight = inputData.weight;

// 简单的 mock 报价逻辑（基于重量）
const baseRate = 1.5; // 每磅 $1.5
const quoteAmount = parseFloat((weight * baseRate).toFixed(2));

// 构造返回数据
return {
  success: true,
  fromAddress: fromAddress,
  toAddress: toAddress,
  weight: weight,
  quoteAmount: quoteAmount,
  status: 'draft',
  message: `Mock 报价已生成：从 ${fromAddress} 到 ${toAddress}，重量 ${weight} lbs`,
  timestamp: new Date().toISOString()
};

